  ('social-worker-moex-00232', 'social-worker', 'social-worker-moex-114-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據老人福利法中，有關老人保護措施之敘述，下列何者錯誤？', '["為發揮老人保護功能，應以地方政府為單位，建立老人保護體系，並定期召開老人保護聯繫會報", "老人因無人扶養、獨居、兩老同居者，地方主管機關應立即依家屬之需求，予以機構緊急安置", "地方主管機關接獲老人保護通報時，應立即處理，必要時得進行訪視調查", "老人之扶養人或其他實際照顧老人者，違反第51條情節嚴重者，應施予4小時以上20小時以 下之家庭教育及輔導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:02+00:00", "source_pdf_sha1": "b5736cd5aeb1", "answer_pdf_sha1": "0dc235ff4e11", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "103", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
